import Foundation

struct Stock {
    let name: String
    let symbol: String
    var quantity: Int
    var price: Double
}

class Portfolio {
    private(set) var stocks: [Stock] = []

    func add(stock: Stock, quantity: Int = 1) {
        let newStock = Stock(name: stock.name, symbol: stock.symbol, quantity: stock.quantity + quantity, price: stock.price)
        stocks.append(newStock)
    }

    func remove(stock: Stock, quantity: Int = 1) {
        guard quantity <= stock.quantity else { return }

        stock.quantity -= quantity

        if stock.quantity == 0 {
            stocks.removeAll { $0 === stock }
        }
    }

    var totalValue: Double {
        stocks.reduce(into: 0) { result, stock in
            result += stock.quantity * stock.price
        }
    }
}

class Trade {
    let symbol: String
    let quantity: Int
    let price: Double
    var executed: Bool = false

    init(symbol: String, quantity: Int, price: Double) {
        self.symbol = symbol
        self.quantity = quantity
        self.price = price
    }
}

class TradingAPI {
    func execute(_ trade: Trade, completion: @escaping (Error?) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 2) {
            let error: Error? = nil // Simulate API response with an error
            completion(error)
        }
    }
}

// Example usage
let portfolio = Portfolio()
portfolio.add(stock: Stock(name: "Apple", symbol: "AAPL", quantity: 10, price: 150))
portfolio.add(stock: Stock(name: "Microsoft", symbol: "MSFT", quantity: 5, price: 230))
print("Initial Portfolio Value: \(portfolio.totalValue)")

let trade = Trade(symbol: "AAPL", quantity: 2, price: 155)
let tradingAPI = TradingAPI()
tradingAPI.execute(trade) { error in
    if let error = error {
        print("Error executing trade: \(error.localizedDescription)")
    } else {
        print("Trade executed successfully.")
        portfolio.add(stock: Stock(name: "Apple", symbol: "AAPL", quantity: trade.quantity, price: trade.price))
        print("Updated Portfolio Value: \(portfolio.totalValue)")
    }
}